ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT ?title WHERE {
  ?movie a :Movie .
  ?movie p:title ?title .
  ?movie p:Crime_Fiction ?crime_fiction_w .
  ?movie p:Crime_Fiction ?crime_fiction_w2 .
  ?movie p:Studio ?studio_w .
  FILTER((((STR(?crime_fiction_w) = "Mystery" || STR(?crime_fiction_w2) = "Thriller")) && STR(?studio_w) = "Warner Bros"))
} }
  low: { SELECT ?title WHERE {
  ?movie a :Movie .
  ?movie p:title ?title .
  ?movie p:Crime_Fiction ?crime_fiction_w .
  ?movie p:Crime_Fiction ?crime_fiction_w2 .
  ?movie p:Studio ?studio_w .
  FILTER((STR(?crime_fiction_w) = "Mystery" || (STR(?crime_fiction_w2) = "Thriller" && STR(?studio_w) = "Warner Bros")))
} }
}
